import React, { useState, useRef, useEffect } from 'react';
import './NumberKeyboard.css';

const NumberKeyboard = () => {
  // باقي الكود زي ما هو، بس تستخدم الكلاسات بدل inline styles
  // ...
  return (
    <div style={{ position: 'relative', padding: '50px', maxWidth: '300px', margin: 'auto' }}>
      <input
        ref={inputRef}
        type="text"
        value={inputValue}
        onFocus={handleInputFocus}
        readOnly
        placeholder={isArabic ? 'أدخل رقم' : 'Enter number'}
        className="input-style"
      />
      {showKeyboard && (
        <div ref={keyboardRef} className="keyboard-container">
          {renderDigits().map((button, index) => (
            <button
              key={index}
              onClick={() => handleButtonClick(button.props.children)}
              className="digit-button"
            >
              {button.props.children}
            </button>
          ))}
          <button onClick={toggleLanguage} className="toggle-btn">
            {isArabic ? 'إنجليزي' : 'عربي'}
          </button>
        </div>
      )}
    </div>
  );
};

export default NumberKeyboard;
